:root {
  color-scheme: light;

  --color-primary-blue-dark: #002468;
  --color-primary-blue-darker: #0640ac;
  --color-primary-blue-transparent: rgb(7 94 255 / 50%);
  --color-primary-blue: #075eff;
  --color-primary-blue-lighter: #c3d7ff;
  --color-primary-blue-lighter-transparent: rgb(195 215 255 / 50%);
  --color-primary-blue-light: #f3f7ff;

  --color-primary-green-dark: #044e1d;
  --color-primary-green-darker: #007025;
  --color-primary-green: #00aa39;

  --color-gray-1: #616161;
  --color-gray-transparent: rgb(164 166 172 / 50%);
  --color-gray-2: #a4a6ac;
  --color-gray-3: #ced2da;
  --color-gray-4: #e7e9ef;

  --color-error-red: #e30008;
  --color-error-red-transparent: rgb(227 0 8 / 50%);

  --color-notify-orange: #ed6b00;

  --color-black: #8b8787;
  --color-white: #ffffff;

  --line-height-ratio: 1.55;
  --line-height-ratio-small: 1.2;
  --line-height-ratio-medium: 1.3;

  --width-desktop: 1232px;
  --width-mobile: 320px;
  --width-current: clamp(var(--width-mobile), 100%, var(--width-desktop));

  --color-background: var(--color-primary-blue-light);
  --color-foreground: #fff;
  --color-border: var(--color-gray-4);
  --color-border-subtle: var(--color-gray-3);
  --color-text: #000;
  --color-text-subtle: var(--color-gray-2);
  --color-text-muted: var(--color-gray-1);
  --color-link: var(--color-primary-blue);
  --color-link-hover: var(--color-primary-blue-darker);

  --color-panel-background: var(--color-primary-blue-light);

  --color-input-background: var(--color-foreground);
  --color-input-border: var(--color-gray-2);
  --color-input-border-hover: var(--color-primary-blue-transparent);
  --color-input-border-active: var(--color-primary-blue);

  --color-button-primary: var(--color-primary-blue);
  --color-button-primary-hover: var(--color-primary-blue-darker);
  --color-button-primary-active: var(--color-primary-blue-dark);
  --color-button-secondary: var(--color-primary-green);
  --color-button-secondary-hover: var(--color-primary-green-darker);
  --color-button-secondary-active: var(--color-primary-green-dark);
  --color-button-text-on-primary: var(--color-white);

  --color-button-transparent-bg: var(--color-primary-blue-light);
  --color-button-transparent-text: var(--color-primary-blue);
  --color-button-transparent-hover: var(--color-primary-blue-lighter);
  --color-button-transparent-active: var(--color-primary-blue-transparent);

  --color-button-icon-bg: var(--color-primary-blue-light);
  --color-button-icon-text: var(--color-primary-blue);
  --color-button-icon-hover: var(--color-primary-blue-lighter);
  --color-button-icon-active: var(--color-primary-blue-transparent);

  --color-button-chips-bg: var(--color-white);
  --color-button-chips-text: var(--color-primary-blue-transparent);
  --color-button-chips-border: var(--color-primary-blue-transparent);
  --color-button-chips-hover-bg: var(--color-primary-blue);
  --color-button-chips-hover-text: var(--color-white);
  --color-button-chips-active-bg: var(--color-primary-blue-transparent);
  --color-button-chips-active-text: var(--color-primary-blue);
