.au-button {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  height: 42px;
  border: none;
  border-radius: 10px;
  padding: 0 22px;
  color: var(--color-button-text-on-primary);
  font-size: 16px;
  line-height: calc(1em * var(--line-height-ratio));
  font-weight: 600;
  transition: background-color 0.3s ease;
  cursor: pointer;
  white-space: nowrap;

  &--primary {
    background-color: var(--color-button-primary);

    &:hover {
      background-color: var(--color-button-primary-hover);
    }

    &:active {
      background-color: var(--color-button-primary-active);
    }
  }

  &--secondary {
    background-color: var(--color-button-secondary);

    &:hover {
      background-color: var(--color-button-secondary-hover);
    }

    &:active {
      background-color: var(--color-button-secondary-active);
    }
  }

  &--transparent {
    background-color: var(--color-button-transparent-bg);
    color: var(--color-button-transparent-text);

    &:hover {
      background-color: var(--color-button-transparent-hover);
    }

    &:active {
      background-color: var(--color-button-transparent-active);
    }
  }

  &--delete {
    color: var(--color-error-red);
  }

  &--icon {
    background-color: var(--color-button-icon-bg);
    color: var(--color-button-icon-text);
    width: 38px;
    height: 38px;
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0;

    &.au-button--small {
      width: 28px;
      height: 28px;
    }

    &:hover {
      background-color: var(--color-button-icon-hover);
    }

    &:active {
      background-color: var(--color-button-icon-active);
    }

    &.au-button--medium {
      min-width: unset;
      width: 42px;
      height: 42px;
    }
  }

  &--link {
    width: fit-content;
    height: fit-content;
    border: none;
    background-color: transparent;
    color: var(--color-link);
    font-size: 14px;
    line-height: 1.2em;
    font-weight: 600;
    padding: 0;

    &:hover {
      color: var(--color-link-hover);
    }

    &:active {
      color: var(--color-button-primary-active);
    }

    &.au-button--medium {
      min-width: unset;
      width: 42px;
      height: 42px;
    }
  }

  &--chips {
    border: 1px solid var(--color-button-chips-border);
    height: 32px;
    font-size: 12px;
    border-radius: 16px;
    color: var(--color-button-chips-text);
    background-color: var(--color-button-chips-bg);

    &:hover {
      color: var(--color-button-chips-hover-text);
      background-color: var(--color-button-chips-hover-bg);
    }

    &:active {
      color: var(--color-button-chips-active-text);
