.au-field {
  position: relative;
  width: 100%;
  display: flex;
  flex-direction: column;
  font-weight: 500;
  font-size: 16px;

  &__error {
    font-weight: 400;
    font-size: 11px;
    color: var(--color-error-red);
    min-height: 14px;
    line-height: var(--line-height-ratio-small);
    margin-top: 4px;
  }

  &__label {
    max-width: 280px;
    height: auto;
    margin-bottom: 6px;
    font-size: 16px;
    font-weight: 500;
    line-height: calc(1em * var(--line-height-ratio-small));
  }

  &__input-wrapper {
    position: relative;
    width: 100%;

    .au-field--clear & > button {
      position: absolute;
      left: 1em;
      cursor: pointer;
      padding: 0;
      color: var(--color-placeholder);
      z-index: 1;
      top: 50%;
      transform: translateY(-50%);

      &:hover {
        color: var(--color-text-subtle);
      }

      &:active {
        color: var(--color-gray-transparent);
      }
    }

    .au-field--clear & .au-field__input {
      padding-left: 2.375em;
    }
  }

  &__group {
    display: grid;
    grid-template-columns: 1fr 141px;
    gap: 10px;
  }

  & input {
    padding: 0 16px;
  }

  &__input {
    width: 100%;
    background: var(--color-input-background);
    border-radius: 12px;
    border: 1px solid var(--color-input-border);
    font-weight: 500;
    font-size: 14px;
    height: 3em;
    line-height: calc(1em * var(--line-height-ratio));
    caret-color: var(--color-primary-blue-lighter);

    &::-webkit-contacts-auto-fill-button {
      background: currentColor;
    }

    &:focus-visible {
      outline: none;
    }

    &:hover {
      border-color: var(--color-input-border-hover);
    }

    &:active,
    &:focus {
      border-color: var(--color-input-border-active);
    }

    &::placeholder {
      font-weight: 400;
      font-size: 14px;
      line-height: calc(1em * var(--line-height-ratio));
      color: var(--color-placeholder);
    }
  }

  &--error > &__input {
    border-color: var(--color-error-red-transparent);
  }

  @media (width < 60rem) {
    &__input {
      height: 3em;
    }
  }
}

