.auth-form__container {
  display: flex;
  width: 100%;
  justify-content: center;
  align-items: center;
  max-width: 587px;
  padding: 72px 24px;
  background-color: var(--color-foreground);
  border: 1px solid var(--color-border);
  border-radius: 40px;
  box-shadow: 0 0 30px 0 rgba(179, 179, 179, 0.25);
  margin: 0 16px;
  min-height: 507px;
}

.auth-form__content {
  width: 100%;
  max-width: 375px;
}

.auth-form__header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  flex-wrap: wrap-reverse;
  gap: 8px;
  margin-bottom: 24px;
}

.auth-form__logo {
  flex: 0 0 113px;
  height: 36px;
  background-color: var(--color-border);
  border-radius: 6px;
}

.auth-form__description {
  font-weight: 400;
  font-size: 16px;
  line-height: calc(1em * var(--line-height-ratio));
  margin-bottom: 24px;
}

.auth-form__form {
  margin-bottom: 20px;
}

.auth-form__input {
  margin-bottom: 14px;
}

.auth-form__footer {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  align-items: center;
  width: 100%;
  font-weight: 400;
  line-height: calc(1em * var(--line-height-ratio));
  color: var(--color-text-subtle);
  text-align: center;
}

@media (max-width: 22.5rem) {
  .auth-form__container {
    border-radius: 36px;
    min-height: 489px;
  }
}

