file.content:
.au-field {
  & .au-checkbox {
    display: flex;
    flex-direction: row;
    align-items: center;
    justify-content: flex-start;
    border: none;
    gap: 8px;

    & label {
      white-space: nowrap;
      font-size: 12px;
      font-weight: 400;
      color: var(--color-text-subtle);
    }
  }
}

.au-checkbox {
  & input {
    opacity: 0;
    position: absolute;
    pointer-events: none;
  }

  &__slider {
    position: relative;
    width: 36px;
    height: 16px;
    background-color: var(--color-placeholder);
    border-radius: 10px;
    transition: background-color 0.3s ease;
    cursor: pointer;

    &::before {
      content: '';
      position: absolute;
      top: -2px;
      left: 0;
      width: 20px;
      height: 20px;
      background-color: white;
      border-radius: 50%;
      border: 1px solid var(--color-primary-blue-lighter);
      transition: transform 0.3s ease;
      box-shadow: 0 0 4px rgba(0, 0, 0, 0.2);
    }
  }

  &--checked &__slider {
    background-color: var(--color-primary-blue);

    &::before {
      transform: translateX(16px);
    }
  }
}
